4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
24	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
25	
26	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
34	  sword: 1000,
35	  amulet: 600,
36	  rune: 250,
37	};
38	
39	type PolicyState = { items: Item[]; remainingCap: number };
40	
41	export function runScenario(input: unknown): unknown {
42	  const { customer, steps } = input as Scenario;
43	  const years = customer?.yearsWithMHPCO ?? 0;
44	  const policies: Record<number, PolicyState> = {};
45	  const results = steps.map((step, index) => {
46	    if (step.op === "claim") return computeClaim(step, policies);
47	    const isFollowUp = index >= 1;
48	    policies[index] = { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items) };
49	    return { premium: computePremium(step.items, years, isFollowUp) };
50	  });
51	  return { results };
52	}
53	
54	function insuranceSumFor(items: Item[]): number {
55	  return items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
56	}
57	
58	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
59	  const policy = policies[step.policy];
60	  const payout = Math.floor(totalReimbursement(step.incident.damages, policy.items));
61	  policy.remainingCap -= payout;
62	  return { payout, remainingCap: policy.remainingCap };
63	}
64	
65	function totalReimbursement(damages: Damage[], items: Item[]): number {
66	  return damages.reduce((sum, damage) => sum + reimbursementFor(damage, items), 0);
67	}
68	
69	function reimbursementFor(damage: Damage, items: Item[]): number {
70	  const item = items.find((i) => i.type === damage.itemType);
71	  const rate = item !== undefined && isHighlyEnchantedForClaim(item) ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : 1;
72	  return Math.max(0, damage.amount * rate - CLAIM_DEDUCTIBLE);
73	}
74	
75	function isHighlyEnchantedForClaim(item: Item): boolean {
76	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
77	}
78	
79	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
80	  if (items.length === 0) return PROCESSING_FEE;
81	  if (items.every(isComponent)) return componentsPremium(items);
82	  return mainItemsPremium(items, years, isFollowUp);
83	}
84	
85	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
86	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
87	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
88	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
89	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
90	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
91	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
92	}
93	
94	function itemSubtotal(item: Item): number {
95	  const base = BASE_PREMIUM_BY_TYPE[item.type];
96	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
97	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
98	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
99	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
100	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
101	}
102	
103	function isHighlyEnchanted(item: Item): boolean {
104	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
105	}
106	
107	function componentsPremium(items: Item[]): number {
108	  const runes = items.filter((i) => i.type === "rune").length;
109	  const moonstones = items.filter((i) => i.type === "moonstone").length;
110	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
111	}
112	
113	function componentTypeBase(count: number): number {
114	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
115	}
116	
117	function isComponent(item: Item): boolean {
118	  return item.type === "rune" || item.type === "moonstone";
119	}
120	
121	function premiumFromBase(base: number): number {
122	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
123	}
